enum TransactionType {
    DEPOSIT,
    WITHDRAWAL
}

class TransactionResult {
    private final boolean success;
    private final String message;
    private final BigDecimal updatedBalance;
    private final String transactionId;

    public TransactionResult(boolean success, String message, BigDecimal updatedBalance, String transactionId) {
        this.success = success;
        this.message = message;
        this.updatedBalance = updatedBalance;
        this.transactionId = transactionId;
    }

    public boolean isSuccess() {
        return success;
    }

    public String getMessage() {
        return message;
    }

    public BigDecimal getUpdatedBalance() {
        return updatedBalance;
    }

    public String getTransactionId() {
        return transactionId;
    }
}

class AccountManager {

    private static final String PREFS_NAME = "banking_app_prefs";
    private static final String KEY_BALANCE = "key_balance";

    private final BalanceRepository repository;

    public AccountManager(Context context) {
        this.repository = new BalanceRepository(context.getApplicationContext());
    }

    public synchronized TransactionResult processTransaction(@NonNull TransactionType type, @NonNull BigDecimal amount) {
        BigDecimal balance = repository.getBalance();

        if (amount.compareTo(BigDecimal.ZERO) <= 0) {
            return new TransactionResult(false, "Amount must be greater than zero", balance, "");
        }

        BigDecimal updatedBalance;
        if (type == TransactionType.DEPOSIT) {
            updatedBalance = balance.add(amount);
        } else {
            if (balance.compareTo(amount) < 0) {
                return new TransactionResult(false, "Insufficient funds", balance, "");
            }
            updatedBalance = balance.subtract(amount);
        }

        repository.saveBalance(updatedBalance);
        String transactionId = UUID.randomUUID().toString();
        return new TransactionResult(
                true,
                "Transaction successful. ID: " + transactionId,
                updatedBalance,
                transactionId
        );
    }

    public BigDecimal getCurrentBalance() {
        return repository.getBalance();
    }
}

class BalanceRepository {

    private final android.content.SharedPreferences sharedPreferences;

    public BalanceRepository(Context context) {
        this.sharedPreferences = context.getSharedPreferences(AccountManager.PREFS_NAME, Context.MODE_PRIVATE);
    }

    public BigDecimal getBalance() {
        String balance = sharedPreferences.getString(AccountManager.KEY_BALANCE, "0.00");
        try {
            return new BigDecimal(balance).setScale(2, BigDecimal.ROUND_HALF_UP);
        } catch (Exception e) {
            return new BigDecimal("0.00");
        }
    }

    public void saveBalance(BigDecimal balance) {
        sharedPreferences.edit().putString(AccountManager.KEY_BALANCE, balance.setScale(2, BigDecimal.ROUND_HALF_UP).toPlainString()).apply();
    }
}